#include<bits/stdc++.h>
using namespace std;
const int MAXN=1e5+10;
const int maxn=2e4;
double a[MAXN],b[MAXN],pre[MAXN];
int n;
int s,t;
deque<int>q;
bool check(double mid){
//	cout<<mid<<" ";
	q.clear();
	double maxi=-1e18;
	for(int i=1;i<=n;i++){
		b[i]=a[i]-mid;
	}
	for(int i=1;i<=n;i++){
		b[i]+=b[i-1];
	}
//	cout << mid <<"xx\n";
//	for (int i = 1; i <= n; i++) {
//		cout << b[i] <<" \n"[i == n];
//	}
	q.push_back(0);
	for(int l=1,r=s;r<=n;l++,r++){
		if(q.size())
			maxi=max(maxi,b[r]-b[q.front()]);
		while(q.size()&&q.front()<r-t+1)q.pop_front();
		while(q.size()&&b[l]<b[q.back()])q.pop_back();
	//	cout<<mid<<" "<<maxi<<endl;
		q.push_back(l);
	}
//	for(int i=1;i<=n;i++){
//		long double x=0;
//		if(q.size()){
//			x=pre[q.back()]-pre[q.front()];
//			x /= ( q.back() - q.front() + 1 );
//		}
//		if(q.size()&&q.back()-q.front()+1>=s)maxi=max(maxi,x);
//		q.push_back(i);
//	}
	return maxi>=0;
}
int main()
{
//	ios::sync_with_stdio(false);
//	cin.tie(0);
//	cout.tie(0);
	cin>>n;
	cin>>s>>t;
	for(int i=1;i<=n;i++){
		cin>>a[i];
	}
	double l=-maxn,r=maxn;
	double mid = (l + r)/2;
//	cout<<mid;
	for(int i=1;i<=100;i++){
		mid = (l + r)/2;
		if(check(mid))l=mid;
		else r=mid;
	}
	printf("%.3f",l);
}
